/* ------------------------------------------------------------------ */
/* Raw syscalls (VM convention: v0=num, a0..a2=args, ret in v0).       */
/* ------------------------------------------------------------------ */
static long __sc(long n, long a, long b, long c)
{
    register long v0 __asm__("$2") = n;
    register long a0 __asm__("$4") = a;
    register long a1 __asm__("$5") = b;
    register long a2 __asm__("$6") = c;
    __asm__ volatile("syscall\n"
                     : "+r"(v0)
                     : "r"(a0), "r"(a1), "r"(a2)
                     : "memory");
    return v0;
}

#define SYS_read   0
#define SYS_write  1
#define SYS_open   2
#define SYS_close  3
#define SYS_lseek  8
#define SYS_rename 38
#define SYS_mkdir  39
#define SYS_time   201

ssize_t read(int fd, void *buf, size_t n)  { return __sc(SYS_read, fd, (long)buf, n); }
ssize_t write(int fd, const void *buf, size_t n) { return __sc(SYS_write, fd, (long)buf, n); }
int close(int fd) { return __sc(SYS_close, fd, 0, 0); }
off_t lseek(int fd, off_t off, int whence) { return __sc(SYS_lseek, fd, off, whence); }
int open(const char *path, int flags, ...) { return __sc(SYS_open, (long)path, flags, 0666); }
int mkdir(const char *path, unsigned int mode) { return __sc(SYS_mkdir, (long)path, mode, 0); }
int rename(const char *a, const char *b) { return __sc(SYS_rename, (long)a, (long)b, 0); }
int unlink(const char *path) { (void)path; return 0; }
int access(const char *path, int mode) { (void)path; (void)mode; return -1; }
int isatty(int fd) { (void)fd; return 0; }
unsigned int sleep(unsigned int s) { (void)s; return 0; }
int usleep(unsigned int us) { (void)us; return 0; }
time_t time(time_t *t) { long r = __sc(SYS_time, (long)t, 0, 0); return r; }
int gettimeofday(struct timeval *tv, void *tz) { (void)tz; if (tv) { tv->tv_sec = __sc(SYS_time,0,0,0); tv->tv_usec = 0; } return 0; }

