/* ------------------------------------------------------------------ */
/* Heap allocator: first-fit with coalescing over a static arena.      */
/* ------------------------------------------------------------------ */
#define HEAP_SIZE (24 * 1024 * 1024)
static unsigned char g_heap[HEAP_SIZE] __attribute__((aligned(8)));
typedef struct blk { size_t size; struct blk *next, *prev; int free; } blk_t;
#define ALIGN8(x) (((x) + 7u) & ~((size_t)7u))
static size_t g_hdr;
static blk_t *g_head;
static int g_hinit;

static void heap_setup(void)
{
    g_hdr = ALIGN8(sizeof(blk_t));
    g_head = (blk_t *)g_heap;
    g_head->size = HEAP_SIZE - g_hdr;
    g_head->next = 0;
    g_head->prev = 0;
    g_head->free = 1;
    g_hinit = 1;
}

void *malloc(size_t n)
{
    blk_t *b;
    if (!g_hinit) heap_setup();
    if (n == 0) n = 1;
    n = ALIGN8(n);
    for (b = g_head; b; b = b->next) {
        if (b->free && b->size >= n) {
            if (b->size >= n + g_hdr + 16) {
                blk_t *nb = (blk_t *)((unsigned char *)b + g_hdr + n);
                nb->size = b->size - n - g_hdr;
                nb->free = 1;
                nb->next = b->next;
                nb->prev = b;
                if (b->next) b->next->prev = nb;
                b->next = nb;
                b->size = n;
            }
            b->free = 0;
            return (unsigned char *)b + g_hdr;
        }
    }
    return 0;
}

void free(void *p)
{
    blk_t *b;
    if (!p) return;
    b = (blk_t *)((unsigned char *)p - g_hdr);
    b->free = 1;
    if (b->next && b->next->free) {
        b->size += g_hdr + b->next->size;
        b->next = b->next->next;
        if (b->next) b->next->prev = b;
    }
    if (b->prev && b->prev->free) {
        blk_t *pb = b->prev;
        pb->size += g_hdr + b->size;
        pb->next = b->next;
        if (b->next) b->next->prev = pb;
    }
}

void *calloc(size_t a, size_t b)
{
    size_t t = a * b;
    void *p = malloc(t);
    if (p) memset(p, 0, t);
    return p;
}

void *realloc(void *p, size_t n)
{
    blk_t *b;
    void *np;
    if (!p) return malloc(n);
    if (n == 0) { free(p); return 0; }
    b = (blk_t *)((unsigned char *)p - g_hdr);
    if (b->size >= n) return p;
    np = malloc(n);
    if (np) { memcpy(np, p, b->size); free(p); }
    return np;
}

