    if (*p == '+' || *p == '-') { neg = (*p == '-'); p++; }
    while (isdigit((unsigned char)*p)) { r = r * 10.0 + (*p - '0'); p++; }
    if (*p == '.') {
        double f = 0.1; p++;
        while (isdigit((unsigned char)*p)) { r += (*p - '0') * f; f *= 0.1; p++; }
    }
    if (*p == 'e' || *p == 'E') {
        int esign = 0, ev = 0; p++;
        if (*p == '+' || *p == '-') { esign = (*p == '-'); p++; }
        while (isdigit((unsigned char)*p)) { ev = ev * 10 + (*p - '0'); p++; }
        double m = 1.0; while (ev--) m *= 10.0;
        if (esign) r /= m; else r *= m;
    }
    if (end) *end = (char *)p;
    return neg ? -r : r;
}
double atof(const char *s) { return strtod(s, 0); }

static unsigned long g_rand = 1;
int rand(void) { g_rand = g_rand * 1103515245 + 12345; return (int)((g_rand >> 16) & 0x7fff); }
void srand(unsigned int s) { g_rand = s; }

void qsort(void *base, size_t n, size_t sz, int (*cmp)(const void *, const void *))
{
    /* simple insertion sort; call sites are tiny. */
    unsigned char *a = base, *tmp = malloc(sz);
    size_t i, j;
    if (!tmp) return;
    for (i = 1; i < n; i++) {
        memcpy(tmp, a + i * sz, sz);
        j = i;
        while (j > 0 && cmp(a + (j - 1) * sz, tmp) > 0) {
            memcpy(a + j * sz, a + (j - 1) * sz, sz);
            j--;
        }
        memcpy(a + j * sz, tmp, sz);
    }
    free(tmp);
}
